#!/usr/bin/env python3
"""
验证OpenClaw技能结构的脚本
"""

import os
import sys
import yaml
from pathlib import Path

def validate_skill_structure(skill_path):
    """验证技能目录结构"""
    skill_path = Path(skill_path)

    print(f"验证技能: {skill_path.name}")
    print("=" * 50)

    errors = []
    warnings = []

    # 1. 检查SKILL.md文件
    skill_md = skill_path / "SKILL.md"
    if not skill_md.exists():
        errors.append("❌ 缺少SKILL.md文件")
    else:
        print(f"✅ SKILL.md: {skill_md}")

        # 检查YAML frontmatter
        with open(skill_md, 'r', encoding='utf-8') as f:
            content = f.read()

        if content.startswith('---'):
            try:
                # 提取YAML frontmatter
                parts = content.split('---')
                if len(parts) >= 3:
                    frontmatter = parts[1]
                    data = yaml.safe_load(frontmatter)

                    # 检查必需字段
                    if 'name' not in data:
                        errors.append("❌ SKILL.md中缺少'name'字段")
                    else:
                        print(f"✅ 技能名称: {data['name']}")

                    if 'description' not in data:
                        errors.append("❌ SKILL.md中缺少'description'字段")
                    else:
                        print(f"✅ 技能描述: {data['description'][:100]}...")
                else:
                    errors.append("❌ SKILL.md格式错误，无法解析YAML frontmatter")
            except yaml.YAMLError as e:
                errors.append(f"❌ YAML解析错误: {e}")
        else:
            errors.append("❌ SKILL.md必须以YAML frontmatter开头（---）")

    # 2. 检查目录结构
    expected_dirs = ['scripts', 'references', 'assets']
    for dir_name in expected_dirs:
        dir_path = skill_path / dir_name
        if dir_path.exists():
            # 检查目录是否为空
            items = list(dir_path.iterdir())
            if items:
                print(f"✅ {dir_name}/: 包含{len(items)}个文件")
            else:
                warnings.append(f"⚠️  {dir_name}/目录为空")
        else:
            warnings.append(f"⚠️  缺少{dir_name}/目录（可选）")

    # 3. 检查脚本文件（如果存在）
    scripts_dir = skill_path / "scripts"
    if scripts_dir.exists():
        python_files = list(scripts_dir.glob("*.py"))
        bash_files = list(scripts_dir.glob("*.sh"))

        if python_files:
            print(f"✅ 找到{len(python_files)}个Python脚本")
            for py_file in python_files:
                # 检查文件是否可执行
                if os.access(py_file, os.X_OK):
                    print(f"   ✅ {py_file.name}: 可执行")
                else:
                    warnings.append(f"⚠️  {py_file.name}: 建议添加可执行权限")

        if bash_files:
            print(f"✅ 找到{len(bash_files)}个Bash脚本")

    # 4. 检查文件大小
    total_size = 0
    for file_path in skill_path.rglob("*"):
        if file_path.is_file():
            total_size += file_path.stat().st_size

    print(f"📊 技能总大小: {total_size / 1024:.1f} KB")

    if total_size > 1024 * 1024:  # 1MB
        warnings.append("⚠️  技能文件较大，建议优化")

    # 5. 输出结果
    print("\n" + "=" * 50)
    print("验证结果:")

    if errors:
        print("\n❌ 错误:")
        for error in errors:
            print(f"  {error}")

    if warnings:
        print("\n⚠️  警告:")
        for warning in warnings:
            print(f"  {warning}")

    if not errors and not warnings:
        print("\n🎉 技能验证通过！")
        return True
    elif errors:
        print(f"\n❌ 发现{len(errors)}个错误，请修复后重试")
        return False
    else:
        print(f"\n⚠️  发现{len(warnings)}个警告，建议修复")
        return True

def check_with_trae(skill_path):
    """使用Trae检查技能质量"""
    import subprocess

    skill_path = Path(skill_path)
    skill_name = skill_path.name

    print(f"\n使用Trae检查技能 '{skill_name}'...")

    # 读取SKILL.md内容
    skill_md = skill_path / "SKILL.md"
    if skill_md.exists():
        with open(skill_md, 'r', encoding='utf-8') as f:
            content = f.read()[:1000]  # 限制内容长度

        prompt = f"""请分析以下OpenClaw技能的质量:
技能名称: {skill_name}
技能内容片段:
{content[:500]}...

请提供:
1. 技能描述的清晰度评价
2. 使用说明的完整性评价
3. 改进建议
"""

        try:
            result = subprocess.run(
                ["trae", "chat", prompt],
                capture_output=True,
                text=True,
                timeout=30
            )
            if result.returncode == 0:
                print("Trae分析结果:")
                print(result.stdout[:500] + "..." if len(result.stdout) > 500 else result.stdout)
            else:
                print("Trae分析失败")
        except:
            print("无法连接Trae，跳过分析")

def main():
    if len(sys.argv) != 2:
        print("用法: python validate_skill.py <技能路径>")
        print("示例: python validate_skill.py skills/public/my-skill")
        sys.exit(1)

    skill_path = sys.argv[1]

    if not Path(skill_path).exists():
        print(f"错误: 路径 '{skill_path}' 不存在")
        sys.exit(1)

    # 验证技能结构
    is_valid = validate_skill_structure(skill_path)

    # 使用Trae进行质量检查
    check_with_trae(skill_path)

    if not is_valid:
        sys.exit(1)

if __name__ == "__main__":
    main()

